import { isMonday, nextMonday, formatISO } from 'date-fns'
import React, { useMemo, useCallback, useEffect, useRef } from 'react'
import { Listbox } from '@headlessui/react'
import PropTypes from 'prop-types'
import { useImmer } from 'use-immer'
import { Button, Textbox } from '/src/components'
import {
  ChevronDownIcon,
  DocumentAddIcon,
  DocumentRemoveIcon,
  TagIcon,
  UserRemoveIcon,
  UserAddIcon,
  DocumentIcon,
  FolderOpenIcon,
  DownloadIcon,
} from '@heroicons/react/solid'
import { ProjectTasks } from '/src/components/autogantt/ProjectTasks'
import { CompetencyToggleButton } from '/src/components/autogantt/CompetencyToggleButton'
import { TW_COLOR_CYCLE } from '/src/color'
import { GanttChart } from '/src/components/autogantt/GanttChart'
import { saveAs } from 'file-saver'

const SectionTitle = ({ className, ...restProps }) => (
  <h1 className={`flex items-center gap-4 text-xl font-bold px-4 mb-4 ${className ?? ''}`} {...restProps} />
)
SectionTitle.propTypes = {
  className: PropTypes.string,
}
const SectionTitle2 = ({ className, ...restProps }) => (
  <h2 className={`flex items-center gap-4 font-bold px-4 mb-4 ${className ?? ''}`} {...restProps} />
)
SectionTitle2.propTypes = {
  className: PropTypes.string,
}

const Section = ({ className, ...restProps }) => <div className={`px-4 ${className}`} {...restProps} />
Section.propTypes = {
  className: PropTypes.string,
}

const StackLayer = ({ stackLayer, onChange, onRemove, ...restProps }) => (
  <div className="flex gap-1 items-center mb-2" {...restProps}>
    <Textbox
      value={stackLayer.label}
      onChange={(e) => {
        onChange?.('label', e)
      }}
    />
    <Button variant="text" className="px-2 text-red-600" onClick={onRemove}>
      &mdash; Remove
    </Button>
  </div>
)
StackLayer.propTypes = {
  stackLayer: PropTypes.object.isRequired,
  onChange: PropTypes.func,
  onRemove: PropTypes.func,
}

const Project = ({ index, projects, project, onRemove, onChange, onChangePriority, ...restProps }) => (
  <div className="flex items-center gap-2 mb-4" {...restProps}>
    <div className={`${TW_COLOR_CYCLE[project.id % TW_COLOR_CYCLE.length].join(' ')} rounded-full p-2`}></div>
    <Listbox value={index} onChange={(value) => onChangePriority?.(value)}>
      <div className="relative">
        <Listbox.Button className="bg-white border z-0 relative cursor-pointer rounded-lg py-2 pl-3 pr-10 hover:bg-slate-50 text-left focus:outline-none focus-visible:border-indigo-500 focus-visible:ring-2 focus-visible:ring-white focus-visible:ring-opacity-75 focus-visible:ring-offset-2 focus-visible:ring-offset-indigo-300">
          <span className="block truncate">Priority: {index + 1}</span>
          <span className="pointer-events-none absolute inset-y-0 right-0 flex items-center pr-2">
            <ChevronDownIcon className="h-5 w-5 text-primary-600" aria-hidden="true" />
          </span>
        </Listbox.Button>
        <Listbox.Options className="shadow-lg shadow-slate-600/10 z-10 absolute mt-1 max-h-60 w-full overflow-auto rounded-md bg-white py-1 text-base ring-1 ring-black ring-opacity-5 focus:outline-none">
          <div className="px-4">Move to</div>
          {projects.map((_, n) => (
            <Listbox.Option
              key={n}
              className={({ active }) =>
                `relative cursor-pointer select-none py-2 text-center ${
                  active ? 'bg-primary-100 text-primary-900' : 'text-gray-900'
                }`
              }
              value={n}
            >
              {({ selected }) => (
                <span className={`block truncate ${selected ? 'font-medium' : 'font-normal'}`}>{n + 1}</span>
              )}
            </Listbox.Option>
          ))}
        </Listbox.Options>
      </div>
    </Listbox>
    <Textbox
      value={project.title}
      onChange={(e) => {
        onChange?.('title', e)
      }}
      placeholder={`Project name (ID: ${project.id})`}
    />
    <Button onClick={onRemove} variant="text" className="px-2 gap-2 text-red-600">
      <DocumentRemoveIcon className="w-6" /> Remove
    </Button>
  </div>
)
Project.propTypes = {
  index: PropTypes.number,
  projects: PropTypes.array,
  project: PropTypes.object.isRequired,
  onChange: PropTypes.func,
  onChangePriority: PropTypes.func,
  onRemove: PropTypes.func,
}

const TeamMember = ({ member, stackLayers, onChange, onRemove, ...restProps }) => {
  const competenciesSet = useMemo(() => new Set(member.competencies), [member.competencies])
  return (
    <div className="flex items-center gap-2 mb-4" {...restProps}>
      <div>
        <Textbox
          placeholder="Give member a name"
          value={member.name}
          onChange={(e) => {
            onChange?.('name', e)
          }}
        />
      </div>
      <div>
        <div className="flex items-center gap-2">
          <Textbox
            inputProps={{ className: 'text-right' }}
            value={member.capacity ?? 3}
            onChange={(e) => {
              onChange?.('capacity', e)
            }}
            type="number"
            min="0"
            max="100"
            step={1}
            suffix="SP / Day"
          />
        </div>
      </div>
      <div className="flex gap-1 items-center h-10">
        {stackLayers
          .filter((sl) => sl?.label?.length)
          .map((stackLayer) => (
            <CompetencyToggleButton
              key={stackLayer.id}
              isToggled={competenciesSet.has(stackLayer.id)}
              onClick={() => onChange('competencies', [stackLayer.id, !competenciesSet.has(stackLayer.id)])}
            >
              {stackLayer.label}
            </CompetencyToggleButton>
          ))}
      </div>
      <div>
        <Button onClick={onRemove} variant="text" className="gap-2 text-red-600 px-2">
          <UserRemoveIcon className="w-6" /> Remove
        </Button>
      </div>
    </div>
  )
}
TeamMember.propTypes = {
  member: PropTypes.object.isRequired,
  stackLayers: PropTypes.arrayOf(PropTypes.object).isRequired,
  onChange: PropTypes.func,
  onRemove: PropTypes.func,
}

const INITIAL_STATE = {
  stackLayerIdCounter: 4,
  stackLayers: [
    { id: 1, label: 'backend' },
    { id: 2, label: 'frontend' },
  ],
  teamMemberIdCounter: 1,
  teamMembers: [],
  projectIdCounter: 1,
  projectTaskIdCounter: 1,
  projects: [],
}
const Page = () => {
  const [state, setState] = useImmer(INITIAL_STATE)

  const handleNewScenario = useCallback(() => {
    setState(INITIAL_STATE)
  }, [setState])

  const handleAddStackLabel = useCallback(() => {
    setState((draftState) => {
      draftState.stackLayers.push({
        id: draftState.stackLayerIdCounter++,
        label: '',
      })
    })
  }, [setState])
  const handleRemoveStackLayer = useCallback((index) => {
    setState((draftState) => {
      draftState.stackLayers.splice(index, 1)
    })
  })

  const handleAddTeamMember = useCallback(() => {
    setState((draftState) => {
      draftState.teamMembers.push({
        id: draftState.teamMemberIdCounter++,
        name: '',
        competencies: draftState.stackLayers.map(({ id }) => id),
      })
    })
  }, [setState])

  const handleRemoveTeamMember = useCallback((index) => {
    setState((draftState) => {
      draftState.teamMembers.splice(index, 1)
    })
  })

  const handleChangeTeamMember = useCallback(
    (index, field, value) => {
      setState((draftState) => {
        const member = draftState.teamMembers[index]
        if (field === 'competencies') {
          const [competencyId, shouldBeToggled] = value
          if (shouldBeToggled) {
            member.competencies.push(competencyId)
          } else {
            member.competencies = member.competencies.filter((competencyId_) => competencyId_ !== competencyId)
          }
          return
        }
        member[field] = value
      })
    },
    [setState]
  )

  const handleChangeStackLabel = useCallback(
    (index, field, value) => {
      setState((draftState) => {
        draftState.stackLayers[index][field] = value
      })
    },
    [setState]
  )

  const handleAddProject = useCallback(() => {
    setState((draftState) => {
      draftState.projects.push({
        id: draftState.projectIdCounter++,
        title: '',
      })
    })
  }, [setState])

  const handleChangeProjectPriority = useCallback(
    (index, newIndex) => {
      setState((draftState) => {
        if (index === newIndex) {
          return
        }
        const { projects } = draftState
        const targetProject = projects[index]
        projects.splice(newIndex > index ? newIndex + 1 : newIndex, 0, targetProject)
        projects.splice(newIndex > index ? index : index + 1, 1)
      })
    },
    [setState]
  )

  const handleChangeProject = useCallback(
    (index, field, value) => {
      setState((draftState) => {
        draftState.projects[index][field] = value
      })
    },
    [setState]
  )

  const handleRemoveProject = useCallback(
    (index) => {
      setState((draftState) => {
        draftState.projects.splice(index, 1)
      })
    },
    [setState]
  )

  const handleAddTask = useCallback(
    (index) => {
      setState((draftState) => {
        const today = new Date()

        draftState.projects[index].tasks = draftState.projects[index].tasks ?? []
        draftState.projects[index].tasks.push({
          id: draftState.projectTaskIdCounter++,
          startDate: formatISO(isMonday(today) ? today : nextMonday(today), { representation: 'date' }),
          estimate: 3,
        })
      })
    },
    [setState]
  )
  const handleChangeTask = useCallback((index, taskIndex, field, value) => {
    setState((draftState) => {
      if (field === 'blockedBy') {
        const [taskId, isAdd] = value
        const task = draftState.projects[index].tasks[taskIndex]
        task.blockedBy = task.blockedBy ?? []
        if (isAdd) {
          task.blockedBy.push(taskId)
        } else {
          task.blockedBy = task.blockedBy.filter((taskId_) => taskId_ !== taskId)
        }
        return
      }
      draftState.projects[index].tasks[taskIndex][field] = value
    })
  })
  const handleRemoveTask = useCallback(
    (index, taskIndex) => {
      setState((draftState) => {
        draftState.projects[index].tasks = draftState.projects[index].tasks ?? []
        draftState.projects[index].tasks.splice(taskIndex, 1)
      })
    },
    [setState]
  )

  useEffect(() => {
    const storedState = JSON.parse(localStorage.getItem('state'))
    if (storedState) {
      setState(storedState)
    }
  }, [])

  useEffect(() => {
    localStorage.setItem('state', JSON.stringify(state))
  }, [state])

  const tasksMap = useMemo(
    () =>
      state.projects.reduce((acc, project) => {
        for (const task of project.tasks ?? []) {
          acc[task.id] = [project, task]
        }
        return acc
      }, {}),
    [state.projects]
  )
  const fileRef = useRef(null)

  return (
    <main className="w-full h-screen flex flex-col pb-8 overflow-y-auto">
      <div className="bg-white px-4 py-4 mb-8 flex items-center gap-2">
        <Button variant="outline" size="sm" onClick={handleNewScenario}>
          <DocumentIcon className="h-4 w-4 mr-2" /> New
        </Button>
        <Button variant="outline" size="sm" onClick={() => fileRef.current.click()}>
          <FolderOpenIcon className="h-4 w-4 mr-2" /> Load
        </Button>
        <Button
          variant="outline"
          size="sm"
          onClick={() => saveAs(new Blob([JSON.stringify(state)], { type: 'text/json;charset=utf-8' }), 'data.json')}
        >
          <DownloadIcon className="h-4 w-4 mr-2" /> Save
        </Button>
      </div>
      <div className="mb-4">
        <SectionTitle>
          Stack Labels
          <Button variant="contained" onClick={handleAddStackLabel} size="sm">
            <TagIcon className="w-4 mr-1" /> Add
          </Button>
        </SectionTitle>
        <Section className="flex gap-4 flex-wrap">
          {!state.stackLayers.length && (
            <div className="text-sm">
              <>
                Add labels of parts of your stack, such as backend, frontend etc.
                <br />
                Used to map competencies and restrict tasks.
              </>
            </div>
          )}
          {state.stackLayers.map((stackLayer, index) => (
            <StackLayer
              key={stackLayer.id}
              stackLayer={stackLayer}
              onChange={(field, e) => handleChangeStackLabel(index, field, e.target.value)}
              onRemove={() => handleRemoveStackLayer(index)}
            />
          ))}
        </Section>
      </div>
      <div className="py-6 mb-4">
        <SectionTitle className="text-indigo-900">
          Team Members
          <Button size="sm" className="text-white bg-indigo-600" variant="contained" onClick={handleAddTeamMember}>
            <UserAddIcon className="w-4 mr-1" /> Add
          </Button>
        </SectionTitle>
        <Section>
          <div className="text-sm text-indigo-800">{!state.teamMembers.length && <>Add team members</>}</div>
          {state.teamMembers.map((member, index) => (
            <TeamMember
              key={member.id}
              member={member}
              stackLayers={state.stackLayers}
              onChange={(field, e) => handleChangeTeamMember(index, field, e?.target?.value ?? e)}
              onRemove={() => handleRemoveTeamMember(index)}
            />
          ))}
        </Section>
      </div>
      <div className="mb-4">
        <SectionTitle>
          Projects
          <Button size="sm" variant="contained" onClick={handleAddProject}>
            <DocumentAddIcon className="w-4 mr-1" /> Add
          </Button>
        </SectionTitle>
        <Section>
          <div className="text-sm">{!state.projects.length && <>Add projects</>}</div>
          {state.projects.map((project, index) => (
            <Project
              onChange={(field, e) => handleChangeProject(index, field, e.target.value)}
              onChangePriority={(value) => handleChangeProjectPriority(index, value)}
              onRemove={() => handleRemoveProject(index)}
              projects={state.projects}
              key={project.id}
              project={project}
              index={index}
            />
          ))}
        </Section>
      </div>
      <div>
        <SectionTitle2 className="text-md">Project Tasks</SectionTitle2>
        <Section>
          {state.projects.map((project, index) => (
            <ProjectTasks
              onAdd={() => handleAddTask(index)}
              onRemove={(taskIndex) => handleRemoveTask(index, taskIndex)}
              onChange={(taskIndex, field, value) => handleChangeTask(index, taskIndex, field, value)}
              index={index}
              key={project.id}
              project={project}
              projects={state.projects}
              stackLayers={state.stackLayers}
              tasksMap={tasksMap}
            />
          ))}
        </Section>
      </div>
      <GanttChart projects={state.projects} teamMembers={state.teamMembers} />
      <input
        className="hidden"
        type="file"
        accept="application/json"
        ref={fileRef}
        onChange={(e) => {
          const fileReader = new FileReader()
          fileReader.readAsText(e.target.files[0], 'UTF-8')
          fileReader.onload = (e) => {
            setState(JSON.parse(e.target.result))
          }
        }}
      />
    </main>
  )
}

export default Page
