import React, { useMemo } from 'react'
import { Listbox } from '@headlessui/react'
import PropTypes from 'prop-types'
import { Button, Textbox } from '/src/components'
import { CompetencyToggleButton } from './CompetencyToggleButton'

const BlockedByList = ({ projects, tasksMap, task, onChange }) => {
  const { blockedBy = [] } = task
  const blockedBySet = useMemo(() => new Set(blockedBy), [blockedBy])
  const projectTasksList = useMemo(
    () =>
      projects.map((project_) => {
        const tasks = project_.tasks ?? []
        return [project_, tasks.filter(({ id }) => !blockedBySet.has(id) && id !== task.id)]
      }),
    [projects]
  )

  return (
    <div className="inline-flex flex-col rounded-lg border items-center">
      <div className="flex px-4 py-2 items-center gap-2">
        <span className="text-xs font-bold">Blocked By</span>
        {blockedBy.map((id) => {
          const [project, task] = tasksMap[id]
          return (
            <div className="border border-red-500 inline-flex rounded-full text-xs overflow-hidden" key={id}>
              <div className="py-1 px-2">{project.title}</div>
              <div className="py-1 px-2 bg-red-50">{task.name ?? <>No name task (ID: {task.id})</>}</div>
              <button className="py-1 px-2 bg-red-50 cursor-pointer no-select" onClick={() => onChange?.([id, false])}>
                &times;
              </button>
            </div>
          )
        })}
        <Listbox onChange={(value) => onChange?.([value, true])}>
          <div className="relative">
            <Listbox.Button className="py-1 px-3 rounded-lg text-xs dark:text-slate-50 text-slate-900 border-transparent active:bg-zinc-900/10 hover:bg-slate-900/5 ml-1">
              +
            </Listbox.Button>
            <Listbox.Options className="shadow-lg shadow-slate-600/10 z-10 w-auto absolute mt-1 max-h-60 overflow-auto rounded-md bg-white py-1 text-base ring-1 ring-black ring-opacity-5 focus:outline-none">
              {projectTasksList.map(
                ([project_, tasks]) =>
                  tasks.length > 0 && (
                    <div className="mb-3" key={project_.id}>
                      <div className="text-xs font-light my-1 px-2" key={project_.id}>
                        {project_.title || <>No title project (ID: {project_.id})</>}
                      </div>
                      {tasks.map((task_) => (
                        <Listbox.Option
                          value={task_.id}
                          className={({ active }) =>
                            `min-w-max relative cursor-pointer select-none px-3 py-2 text-center ${
                              active ? 'bg-primary-100 text-primary-900' : 'text-gray-900'
                            }`
                          }
                          key={task_.id}
                        >
                          {task_.name ?? <>No name task (ID: {task_.id})</>}
                        </Listbox.Option>
                      ))}
                    </div>
                  )
              )}
            </Listbox.Options>
          </div>
        </Listbox>
      </div>
    </div>
  )
}
BlockedByList.propTypes = {
  projects: PropTypes.array.isRequired,
  task: PropTypes.object.isRequired,
  onChange: PropTypes.func.isRequired,
  tasksMap: PropTypes.object.isRequired,
}

const SectionTitle = ({ className, ...restProps }) => (
  <h3 className={`flex items-center gap-4 text-xl px-4 mb-4 ${className ?? ''}`} {...restProps} />
)
SectionTitle.propTypes = {
  className: PropTypes.string,
}
const Section = ({ className, ...restProps }) => <div className={`px-4 ${className ?? ''}`} {...restProps} />
Section.propTypes = {
  className: PropTypes.string,
}

export const ProjectTasks = ({ stackLayers, projects, tasksMap, project, onAdd, onRemove, onChange }) => {
  return (
    <div className="mb-4">
      <SectionTitle>
        {project.title?.length ? project.title : <>No title project (ID: {project.id})</>}{' '}
        <Button variant="outline" size="sm" onClick={onAdd}>
          + Add
        </Button>
      </SectionTitle>
      <Section>
        {(project.tasks ?? []).map((task, taskIndex) => (
          <div className="mb-4" key={task.id}>
            <div className="flex gap-2 items-center mb-1" key={task.id}>
              <Textbox
                placeholder={`Task name (ID: ${task.id})`}
                value={task.name}
                onChange={(e) => onChange?.(taskIndex, 'name', e.target.value)}
              />
              <Textbox
                inputProps={{ className: 'text-right' }}
                type="number"
                min={1}
                step={1}
                value={task.estimate ?? 1}
                onChange={(e) => onChange?.(taskIndex, 'estimate', parseInt(e.target.value))}
                suffix="SP"
              />
              <Textbox
                prefix={<span className="text-xs font-bold mr-4">Starts on</span>}
                type="date"
                step="7"
                value={task.startDate}
                onChange={(e) => onChange?.(taskIndex, 'startDate', e.target.value)}
              />
              <div className="flex gap-1 items-center">
                {stackLayers.map((layer) => (
                  <CompetencyToggleButton
                    key={layer.id}
                    isToggled={task.stackLayerId === layer.id}
                    onClick={() => onChange(taskIndex, 'stackLayerId', layer.id)}
                  >
                    {layer.label}
                  </CompetencyToggleButton>
                ))}
              </div>
              <Button className="px-2 text-red-600" variant="text" onClick={() => onRemove?.(taskIndex)}>
                &mdash; Remove
              </Button>
            </div>
            <BlockedByList
              tasksMap={tasksMap}
              projects={projects}
              project={project}
              task={task}
              onChange={(value) => {
                onChange?.(taskIndex, 'blockedBy', value)
              }}
            />
          </div>
        ))}
      </Section>
    </div>
  )
}

ProjectTasks.propTypes = {
  project: PropTypes.object.isRequired,
  projects: PropTypes.array.isRequired,
  stackLayers: PropTypes.array.isRequired,
  onChange: PropTypes.func,
  onAdd: PropTypes.func,
  onRemove: PropTypes.func,
  tasksMap: PropTypes.object.isRequired,
}
